function AddPago()
{
	var Nrocode=0;
	var Nrocode2=0;
	for (var i=0; i<Ctrl('MAIN_GRID_PAGOS').TotalRowsCount(); i++)
		 Nrocode = Ctrl("MAIN_GRID_PAGOS").GetCellXValue('c_modo_de_pago', i);
		 Nrocode2 = Ctrl("MAIN_GRID_PAGOS").GetCellXValue('f_pago', i);
	Ctrl('MAIN_GRID_PAGOS').AddNew();
	var MyControl = Ctrl("MAIN_GRID_PAGOS").GetCellSelectedControl("c_modo_de_pago");	
	MyControl.SetXValue(Number(Nrocode)+1);
	var MyControl2 = Ctrl("MAIN_GRID_PAGOS").GetCellSelectedControl("f_pago");

	Now=new Date();
	day  =Now.getDate();
	month=Now.getMonth()+1; 
	year =Now.getFullYear();

	/*alert(day);
	alert(month);
	alert(year);*/		

	if(month.length == 1){
		month = "0"+month;
		alert("mes distinto de 2");
		alert(month);
	}
	if(day.length == 1){
		alert("día distinto de 2");
		day = "0"+day;
		alert(day);
	}

	Nrocode2 =  day+"/"+month+"/"+year;
	//MyControl2.SetXValue(Nrocode2);
	MyControl2.SetCValue(Nrocode2);	 
}

function DelPago()
{	
	var code = Ctrl("MAIN_GRID_PAGOS").GetCellSelectedXValue("c_modo_de_pago");
	for (var i=0; i<Ctrl('MAIN_GRID').TotalRowsCount(); i++)
	{
		if (Ctrl("MAIN_GRID").GetCellXValue('c_modo_de_pago', i) == code)
			Ctrl("MAIN_GRID").SetCellXValue('c_modo_de_pago', i, "");
	}
	Ctrl('MAIN_GRID_PAGOS').Del();	
}

function ACCEPT()
{  	 
		//Valido que haya completado al menos un detalle y que este bien completo
		  var cantIncompletos = 0; 

		  for (var a=0; a<Ctrl('MAIN_GRID').TotalRowsCount(); a++)
		  {

			  if(Ctrl("MAIN_GRID").GetCellXValue('n_importe',a)=="") 
			  	{
			  	cantIncompletos++;
			  	} 

			  if ( (Ctrl("MAIN_GRID").GetCellXValue('n_importe',a)!="")	&& (Ctrl("MAIN_GRID").GetCellXValue('c_modo_de_pago',a)==""))
			  	{
			  	b = a+1;
			  	alert("Complete el código de modo de pago del importe "+b);


			  	return false;      
			  	}		

			  	if ( (Ctrl("MAIN_GRID").GetCellXValue('n_importe',a)=="")	&& (Ctrl("MAIN_GRID").GetCellXValue('c_modo_de_pago',a)!=""))
			  	{
			  	alert("Complete el importe del código de modo de pago "+Ctrl("MAIN_GRID").GetCellXValue('c_modo_de_pago',a));      
			  	return false;
			  	}	


			}

			  if(cantIncompletos==Ctrl('MAIN_GRID').TotalRowsCount())
			  		{
			  		alert("Complete al menos un detalle");
			  		return false;
			  		}

		   /*No VA porque no es relacion 1 --> 1
		   var cantidadCompletosMain = Ctrl('MAIN_GRID').TotalRowsCount() - cantIncompletos;
		   var cantidadFilasDetalle =Ctrl('MAIN_GRID_PAGOS').TotalRowsCount();
		   //Si hay mas completos que filas de detalle, falta agregar detalles
		   if(cantidadCompletosMain > cantidadFilasDetalle)
		   	{
		   	alert("Faltan completar modalidades de pago");
		   	return false;
		   	} 
		   	else
		   	{
		   	//Si hay mas detalles que completos, un detalle es inconsistente
		   	if(cantidadFilasDetalle> cantidadCompletosMain)
		   		{
		   		alert("Existen modalidades de pago que no se corresponden con algún detalle");
		   		return false;
		   		}
		   	}

			*/	  

//Valido que exista almenos un detalle de anticipo por cada modalidad de pago   
 var cantidadFilasAnt =Ctrl('MAIN_GRID').TotalRowsCount();
 var flag = 0;                        
		for (var j=0; j<Ctrl('MAIN_GRID_PAGOS').TotalRowsCount(); j++)
		{
			flag=0;

		  var fecha_pago = Ctrl("MAIN_GRID_PAGOS").GetCellXValue('f_pago',j);
		  if(fecha_pago!="")
			{ 
				/*var regex = /^([0][1-9]|[12][0-9]|3[01])(\/|-)([0][1-9]|[1][0-2])\2(\d{4})$/;
				var resp = regex.test(fecha_pago);
				//resp retorna true si cumple con el regex y false si no cumple
			 	if (resp==false){
			 		alert('El formato de la fecha de pago debe ser dd/mm/aaaa');
					return false;
				}*/

				if(fecha_pago == 'NaN' ){
					alert('El formato de la fecha de pago debe ser dd/mm/aaaa');
					return false;
				}
			}
			else
			{
				alert("Completar la fecha de pago");
				return false;
			} 

		  var codigoMod = Ctrl("MAIN_GRID_PAGOS").GetCellXValue('c_modo_de_pago',j);
			  for (var i=0; i<cantidadFilasAnt; i++)
				  {
				   if (Ctrl("MAIN_GRID").GetCellXValue('c_modo_de_pago', i)!="")
					   {   
						   if (Ctrl("MAIN_GRID").GetCellXValue('c_modo_de_pago', i)==codigoMod)
							   { 									   flag = 1;
									  break;
								  }
              }

				   }
				   if (flag==0)
				   {
					alert("La modalidad de pago "+(j+1)+" no está asignada a ningun detalle de anticipo");
					return false;
				   }
		}		


		//Validacion de correspondencia entre importes y detalles de importe
		var cantidadFilasDetalle =Ctrl('MAIN_GRID_PAGOS').TotalRowsCount();
		for (var i=0; i<Ctrl('MAIN_GRID').TotalRowsCount(); i++) 
		{
			var cantNo=0;
			var importe = Ctrl("MAIN_GRID").GetCellXValue('n_importe', i); 		
			if(importe!="")
			{
				 //Si no es nulo, recupero su codigo y valido que tenga detalle.  
				 var codigoMain =  Ctrl("MAIN_GRID").GetCellXValue('c_modo_de_pago', i);
				 for (var j=0; j<Ctrl('MAIN_GRID_PAGOS').TotalRowsCount(); j++)
				 {
				       if(Ctrl("MAIN_GRID_PAGOS").GetCellXValue('c_modo_de_pago', j)==codigoMain)
				       	{

				       	//Si coincide el codigo, valido que tenga detalle
				       		if(Ctrl("MAIN_GRID_PAGOS").GetCellXValue('o_modo_de_pago',j) =="")
				       			{                                                                	

				       			   alert("El importe con código "+codigoMain+" no tiene detalle de modo de pago");
				       			   return false;
				       			}
				       	}
				       	else
				       	{
				       	//suma la cantidad de filas que no tienen el codigo main
				       	cantNo++;
				       	}
				 } 

				 if(cantNo==cantidadFilasDetalle)
				 		{
				 		  alert("El importe con código "+codigoMain+" no tiene detalle de modo de pago");
				 		  return false;
				 		}



			}

		}
			//Sumo el importe total del adelanto
			var importe = 0;			
			for (var i=0; i<Ctrl('MAIN_GRID').TotalRowsCount(); i++)
				{ 
					importe += Number(Ctrl("MAIN_GRID").GetCellXValue('n_importe', i));
				}
		Ctrl("hid_importe_total").SetXValue(importe); 		

		Ctrl('main').DoEvent("ACCEPT"); 
}

function ADD_MODO_PAGO() {                                                                                         
	//var MyControl = Ctrl("MAIN_GRID").GetCellSelectedControl("oi_modo_de_pago"); 
	//openNewFlowWait("NucleusRH.Base.Legales.Adelantos.flow","MODO_PAGO",'<DATA oi_adelanto="'+Ctrl('hid_oi_adelanto').GetXValue()+'"/>',new ObjectResult(MyControl),"M");
	for (var i=0; i<Ctrl('MAIN_GRID').TotalRowsCount(); i++) {
		if (Ctrl("MAIN_GRID").GetCellXValue('chk_cambio', i) == 1)
		 	Ctrl("MAIN_GRID").SetCellXValue("c_modo_de_pago", i, Ctrl("MAIN_GRID_PAGOS").GetCellSelectedXValue('c_modo_de_pago'));
	}
}

function ObjectResult(control)
{        
	this.MyControl = control;
	this.processResult= function(xmlin)
											{        
												var xmlDoc = new NomadXML(xmlin);
												for (var i=0; i<Ctrl('MAIN_GRID').TotalRowsCount(); i++) {
													if (Ctrl("MAIN_GRID").GetCellXValue('chk_cambio', i) == 1)
													  Ctrl("MAIN_GRID").SetCellXValue("oi_modo_de_pago", i, xmlDoc.GetAttr("oi_modo_de_pago"));
												}
												//this.MyControl.SetXValue(xmlDoc.GetAttr("oi_modo_de_pago")); 
											}											
}
